import UIKit
import Foundation

class UniversalLinkHandler: NSObject, WKNavigationDelegate {
    func webView(_ webView: WKWebView, decidePolicyFor navigationAction: WKNavigationAction, decisionHandler: @escaping (WKNavigationActionPolicy) -> Void) {
        guard let url = navigationAction.request.url else {
            return
        }
        
        // Parse the URL components and navigate to the appropriate view controller
        switch url.pathComponents.last {
        case "profile":
            if let id = Int(url.queryParameters["id"] ?? "") {
                let profileViewController = ProfileViewController()
                profileViewController.userId = id
                navigationController?.pushViewController(profileViewController, animated: true)
            } else {
                // Handle invalid URL or missing ID parameter
            }
        case "payment":
            if let action = url.queryParameters["action"] ?? "" {
                switch action {
                case "confirm":
                    let paymentConfirmationViewController = PaymentConfirmationViewController()
                    navigationController?.pushViewController(paymentConfirmationViewController, animated: true)
                default:
                    // Handle unknown or invalid action parameter
                }
            } else {
                // Handle missing action parameter
            }
        case "admin":
            if let section = url.queryParameters["section"] ?? "" {
                switch section {
                case "settings":
                    let settingsViewController = SettingsViewController()
                    navigationController?.pushViewController(settingsViewController, animated: true)
                default:
                    // Handle unknown or invalid section parameter
                }
            } else {
                // Handle missing section parameter
            }
        default:
            // Handle unknown URL path
        }
        
        decisionHandler(.allow)
